import{_ as t,c as e,o as a,V as r}from"./chunks/framework.35c8bad0.js";const _=JSON.parse('{"title":"requestAnimationFrame()","description":"","frontmatter":{"title":"requestAnimationFrame()","date":"2024-11-08T00:00:00.000Z"},"headers":[],"relativePath":"frontend/webapi-window/241108.md","lastUpdated":1776926682000}'),l={name:"frontend/webapi-window/241108.md"},o=r('<h1 id="requestanimationframe" tabindex="-1">requestAnimationFrame() <a class="header-anchor" href="#requestanimationframe" aria-label="Permalink to &quot;requestAnimationFrame()&quot;">​</a></h1><h2 id="_1-引言" tabindex="-1">1. 引言 <a class="header-anchor" href="#_1-引言" aria-label="Permalink to &quot;1. 引言&quot;">​</a></h2><p><code>requestAnimationFrame</code> 是浏览器提供的<strong>用于在下一次重绘之前执行指定回调函数</strong>的 API。它通常用于创建流畅的 JavaScript 动画，能<strong>自动与浏览器的刷新率同步</strong>（通常是 60Hz，即约 16.6ms 执行一次）。</p><h2 id="_2-工作原理" tabindex="-1">2. 工作原理 <a class="header-anchor" href="#_2-工作原理" aria-label="Permalink to &quot;2. 工作原理&quot;">​</a></h2><ul><li>浏览器每帧都会执行“重绘”操作（例如改变元素位置、样式）。</li><li><code>requestAnimationFrame</code> 将回调放入一个队列，<strong>在每一帧的绘制之前</strong>执行该回调。</li><li>如果回调中再次调用 <code>requestAnimationFrame</code>，就会形成递归循环，持续与屏幕刷新频率保持一致。</li></ul><h2 id="_3-与-settimeout-setinterval-的区别" tabindex="-1">3. 与 <code>setTimeout</code> / <code>setInterval</code> 的区别 <a class="header-anchor" href="#_3-与-settimeout-setinterval-的区别" aria-label="Permalink to &quot;3. 与 `setTimeout` / `setInterval` 的区别&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">对比维度</th><th style="text-align:left;">requestAnimationFrame</th><th style="text-align:left;">setTimeout/setInterval</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>执行时机</strong></td><td style="text-align:left;">帧开始前，由浏览器决定（与屏幕刷新同步）</td><td style="text-align:left;">宏任务队列，按指定延迟执行，与帧无关</td></tr><tr><td style="text-align:left;"><strong>频率</strong></td><td style="text-align:left;">匹配显示器刷新率（通常 60fps）</td><td style="text-align:left;">不可控，即使设为 16.6ms，也可能因事件队列阻塞而漂移</td></tr><tr><td style="text-align:left;"><strong>性能</strong></td><td style="text-align:left;">页面隐藏/非激活时自动暂停，节省 CPU/电量</td><td style="text-align:left;">后台依然执行，浪费资源</td></tr><tr><td style="text-align:left;"><strong>丢帧处理</strong></td><td style="text-align:left;">浏览器会自动合并同帧内的多次 DOM 修改</td><td style="text-align:left;">容易丢帧或产生无效更新</td></tr><tr><td style="text-align:left;"><strong>精确性</strong></td><td style="text-align:left;">高（基于 vsync 信号）</td><td style="text-align:left;">低（受事件循环影响，最小延迟约 4ms）</td></tr></tbody></table><h2 id="_4-优点-为什么用-raf-做动画" tabindex="-1">4. 优点（为什么用 rAF 做动画） <a class="header-anchor" href="#_4-优点-为什么用-raf-做动画" aria-label="Permalink to &quot;4. 优点（为什么用 rAF 做动画）&quot;">​</a></h2><ul><li><strong>流畅</strong>：与刷新率同步，避免掉帧或过度绘制。</li><li><strong>高效</strong>：页面不可见时自动停止，不消耗资源。</li><li><strong>精准时间戳</strong>：回调参数 <code>timestamp</code> 为高精度时间，可用于计算帧间差值。</li><li><strong>批量更新</strong>：浏览器可以合并同一帧内的样式计算和布局，减少重排。</li></ul><h2 id="_5-使用场景" tabindex="-1">5. 使用场景 <a class="header-anchor" href="#_5-使用场景" aria-label="Permalink to &quot;5. 使用场景&quot;">​</a></h2><ul><li><strong>JavaScript 动画</strong>：如移动、缩放、渐变等高频属性修改。</li><li><strong>Canvas/WebGL 渲染</strong>：游戏、粒子效果、实时图表。</li><li><strong>滚动监听优化</strong>：配合滚动事件实现平滑视差效果。</li><li><strong>帧率监测</strong>：计算 FPS。</li><li><strong>与 <code>setTimeout</code> 组合实现限流</strong>：例如在 rAF 中做 DOM 批量更新。</li></ul><h2 id="_6-注意事项-潜在缺点" tabindex="-1">6. 注意事项 / 潜在缺点 <a class="header-anchor" href="#_6-注意事项-潜在缺点" aria-label="Permalink to &quot;6. 注意事项 / 潜在缺点&quot;">​</a></h2><ul><li><strong>需要递归调用</strong>：不像 <code>setInterval</code> 自动重复，必须手动在回调末尾再次调用。</li><li><strong>不适合低频率任务</strong>：例如每隔几秒请求数据，应使用 <code>setInterval</code>。</li><li><strong>兼容性</strong>：IE10 及以上均支持，旧版需降级（<code>setTimeout</code> 回退）。</li><li><strong>高频率回调</strong>：如果回调执行时间超过 16.6ms，会导致丢帧，需优化代码。</li></ul>',13),n=[o];function s(i,d,g,c,h,m){return a(),e("div",null,n)}const f=t(l,[["render",s]]);export{_ as __pageData,f as default};
